package main

import (
	"sort"
)

type UnionFind struct {
	parent []int64
	minNode []int64
}

func NewUnionFind(size int64) *UnionFind {
	parent := make([]int64, size+1)
	minNode := make([]int64, size+1)
	for i := int64(1); i <= size; i++ {
		parent[i] = i
		minNode[i] = i
	}
	return &UnionFind{parent: parent, minNode: minNode}
}

func (uf *UnionFind) Find(x int64) int64 {
	if uf.parent[x] != x {
		uf.parent[x] = uf.Find(uf.parent[x])
	}
	return uf.parent[x]
}

func (uf *UnionFind) Union(x, y int64) {
	rootX := uf.Find(x)
	rootY := uf.Find(y)
	if rootX != rootY {
		if rootX < rootY {
			uf.parent[rootY] = rootX
			if uf.minNode[rootY] < uf.minNode[rootX] {
				uf.minNode[rootX] = uf.minNode[rootY]
			}
		} else {
			uf.parent[rootX] = rootY
			if uf.minNode[rootX] < uf.minNode[rootY] {
				uf.minNode[rootY] = uf.minNode[rootX]
			}
		}
	}
}

func solve(c int64, connections [][]int64, queries [][]int64) []int64 {
	uf := NewUnionFind(c)
	for _, conn := range connections {
		uf.Union(conn[0], conn[1])
	}

	online := make([]bool, c+1)
	for i := int64(1); i <= c; i++ {
		online[i] = true
	}

	componentOnlineNodes := make(map[int64][]int64)
	for i := int64(1); i <= c; i++ {
		root := uf.Find(i)
		componentOnlineNodes[root] = append(componentOnlineNodes[root], i)
	}

	// Sort each component's online nodes for binary search
	for root := range componentOnlineNodes {
		sort.Slice(componentOnlineNodes[root], func(i, j int) bool {
			return componentOnlineNodes[root][i] < componentOnlineNodes[root][j]
		})
	}

	result := []int64{}
	for _, query := range queries {
		typ := query[0]
		x := query[1]
		if typ == 1 {
			if online[x] {
				result = append(result, x)
			} else {
				root := uf.Find(x)
				nodes := componentOnlineNodes[root]
				// Find the smallest online node in the component
				left := 0
				right := len(nodes) - 1
				pos := -1
				for left <= right {
					mid := (left + right) / 2
					if online[nodes[mid]] {
						pos = mid
						right = mid - 1
					} else {
						left = mid + 1
					}
				}
				if pos == -1 {
					result = append(result, -1)
				} else {
