#include <vector>
#include <unordered_map>
#include <set>
#include <algorithm>

using namespace std;

class UnionFind {
private:
    vector<long long> parent;
    vector<long long> minNode;
public:
    UnionFind(long long size) {
        parent.resize(size + 1);
        minNode.resize(size + 1);
        for (long long i = 1; i <= size; ++i) {
            parent[i] = i;
            minNode[i] = i;
        }
    }

    long long find(long long x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    void unionSets(long long x, long long y) {
        long long rootX = find(x);
        long long rootY = find(y);
        if (rootX != rootY) {
            if (rootX < rootY) {
                parent[rootY] = rootX;
                minNode[rootX] = min(minNode[rootX], minNode[rootY]);
            } else {
                parent[rootX] = rootY;
                minNode[rootY] = min(minNode[rootY], minNode[rootX]);
            }
        }
    }

    long long getMinNode(long long x) {
        return minNode[find(x)];
    }
};

vector<long long> solve(long long c, vector<vector<long long>> connections, vector<vector<long long>> queries) {
    UnionFind uf(c);
    for (const auto& conn : connections) {
        uf.unionSets(conn[0], conn[1]);
    }

    vector<bool> online(c + 1, true);
    unordered_map<long long, set<long long>> componentOnlineNodes;
    for (long long i = 1; i <= c; ++i) {
        long long root = uf.find(i);
        componentOnlineNodes[root].insert(i);
    }

    vector<long long> result;
    for (const auto& query : queries) {
        long long type = query[0];
        long long x = query[1];
        if (type == 1) {
            if (online[x]) {
                result.push_back(x);
            } else {
                long long root = uf.find(x);
                auto& nodes = componentOnlineNodes[root];
                if (nodes.empty()) {
                    result.push_back(-1);
                } else {
                    result.push_back(*nodes.begin());
                }
            }
        } else if (type == 2) {
            if (online[x]) {
                online[x] = false;
                long long root = uf.find(x);
                componentOnlineNodes[root].erase(x);
            }
        }
    }
    return result;
}

